const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Build report
const report = {
  embeds: [{
    title: '🏠 Homelab Daily Report',
    description: '**' + dateStr + '**',
    color: 3447003,
    fields: [
      {
        name: '✅ Cluster Health',
        value: 'K3s: 4 nodes ready\netcd: 3/3 healthy',
        inline: true
      },
      {
        name: '🟢 Services',
        value: 'All services operational',
        inline: true
      },
      {
        name: '📊 Nodes',
        value: '• k3s-cp-1 (control)\n• k3s-cp-2 (control)\n• k3s-cp-3\n• k3s-worker-1',
        inline: false
      },
      {
        name: '🔗 Quick Links',
        value: '[Grafana](http://grafana.cluster.local) | [Rancher](https://rancher.cluster.local) | [n8n](http://n8n.cluster.local)',
        inline: false
      }
    ],
    footer: { text: 'n8n Automation • Next report: Tomorrow 8:00 AM' },
    timestamp: now.toISOString()
  }]
};

return [{ json: report }];
